// // This module implements a 4-bit BCD counter that counts down from 9 to 0 and then wraps around to 9.
module BCD_counter_4(
   input                clk ,
   input                rst_n,

   output reg [3:0]     Q  
);
    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) Q <= 4'd0;
        else if(Q == 4'd9) Q <= 4'd0;
        else Q <= Q + 4'd1;
    end
endmodule
